mapper.select:
SELECT er.*, ep.exam_paper_name, ep.exam_paper_myscore AS exam_paper_myscore, ep.exam_paper_types AS exam_paper_types, ei.exam_name, ei.start_time AS exam_schedule_start, ei.end_time AS exam_schedule_end, kemud.index_name AS kemu_value, u.nickname, ei.passing_score, -- 统计该考试记录中是否有简答题 EXISTS ( SELECT 1 FROM exam_details ed LEFT JOIN exam_question eq ON ed.exam_question_id = eq.id WHERE ed.exam_record_id = er.id AND eq.exam_question_types = 5 ) AS hasSubjectiveQuestions, -- 统计待批阅的简答题数量 ( SELECT COUNT(*) FROM exam_details ed LEFT JOIN exam_question eq ON ed.exam_question_id = eq.id WHERE ed.exam_record_id = er.id AND eq.exam_question_types = 5 AND (ed.review_status = 0 OR ed.review_status IS NULL) ) AS pendingReviewCount, -- 统计已批阅的简答题数量（用于区分“待阅卷/阅卷中”，即使给 0 分也算已批阅） ( SELECT COUNT(*) FROM exam_details ed LEFT JOIN exam_question eq ON ed.exam_question_id = eq.id WHERE ed.exam_record_id = er.id AND eq.exam_question_types = 5 AND ed.review_status = 1 ) AS reviewedSubjectiveCount, -- 计算实际考试耗时（分钟） CASE WHEN er.end_time IS NOT NULL AND er.insert_time IS NOT NULL THEN TIMESTAMPDIFF(MINUTE, er.insert_time, er.end_time) ELSE NULL END AS actualDuration FROM exam_record er LEFT JOIN exam_paper ep ON er.exam_paper_id = ep.id LEFT JOIN users u ON er.users_id = u.id LEFT JOIN exam_info ei ON er.exam_info_id = ei.id LEFT JOIN dictionary kemud ON ei.kemu_types = kemud.code_index AND kemud.dic_code = 'kemu_types'
AND IFNULL(er.is_latest, 1) = 1
AND ei.kemu_types = #{req.kemuTypes}
and er.users_id = #{req.usersId}
AND er.exam_info_id = #{req.examInfoId}
and er.exam_record_uuid_number like CONCAT('%',#{req.examRecordUuidNumber},'%')
AND INSTR(IFNULL(ei.exam_name, ''), #{req.examPaperName}) > 0
AND u.nickname LIKE CONCAT('%', #{req.nickname}, '%')
ORDER BY (ei.start_time IS NULL) ASC, ei.start_time DESC, er.insert_time DESC

SELECT COUNT(*) FROM exam_record er
WHERE er.exam_info_id = #{examInfoId}
AND

