mapper.select:
SELECT
    DATE_FORMAT(t.day_d, '%Y-%m-%d') AS dayKey,
    DATE_FORMAT(t.day_d, '%m-%d') AS dayLabel,
    t.avgScore,
    t.passRate
FROM (
    SELECT
        DATE(COALESCE(er.end_time, er.insert_time)) AS day_d,
        AVG(er.total_score) AS avgScore,
        (SUM(CASE WHEN er.total_score >= IFNULL(ei.passing_score, 60) THEN 1 ELSE 0 END) * 100.0 / COUNT(*)) AS passRate
    FROM exam_record er
    INNER JOIN exam_info ei ON er.exam_info_id = ei.id

        er.exam_info_id IS NOT NULL
        AND 
        AND er.total_score IS NOT NULL

            AND ei.id = #{req.examInfoId}


            AND er.status = #{req.status}


            AND DATE(ei.start_time) >= #{req.dateStart}


            AND DATE(ei.start_time) <= #{req.dateEnd}


            AND ei.kemu_types = #{req.kemuTypes}


            AND DATE(COALESCE(er.end_time, er.insert_time)) >= #{trendStart}


            AND DATE(COALESCE(er.end_time, er.insert_time)) <= #{trendEnd}


    GROUP BY DATE(COALESCE(er.end_time, er.insert_time))
) t
ORDER BY t.day_d ASC
